// src/pages/CustomerDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(localStorage.getItem("user") || "{}");

  const [requests, setRequests] = useState([]);
  const [workers, setWorkers] = useState([]);

  const [form, setForm] = useState({
    workType: "",
    labourId: "",
    labourName: "",
    location: "",
    date: ""
  });

  const jobs = [
    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"
  ];

  useEffect(() => {
    getRequests();
  }, []);

  // GET REQUESTS
  const getRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/customer/${user.name}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  // SEARCH WORKERS
  const searchWorkers = async (workType) => {
    try {
      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter(w =>
        w.skills.includes(workType)
      );

      setWorkers(filtered);

    } catch (err) {
      console.log(err);
    }
  };

  // SEND REQUEST
  const sendRequest = async () => {
    if (!form.workType || !form.labourId || !form.location || !form.date) {
      return alert("Fill all fields");
    }

    try {
      await axios.post(
        "http://localhost:5000/api/request/send",
        {
          customerName: user.name,
          customerId: user._id,
          labourId: form.labourId,
          labourName: form.labourName,
          workType: form.workType,
          location: form.location,
          date: form.date,
          timings: ["9AM - 12PM"]
        }
      );

      setForm({
        workType: "",
        labourId: "",
        labourName: "",
        location: "",
        date: ""
      });

      setWorkers([]);
      getRequests();

    } catch (err) {
      console.log(err);
    }
  };

  // DECISION
  const customerDecision = async (id, decision) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/customer-decision/${id}`,
        { decision }
      );
      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  // FEEDBACK
  const submitFeedback = async (id, rating, comment) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/feedback/${id}`,
        {
          rating: Number(rating),
          comment
        }
      );
      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        {/* LEFT PANEL */}
        <div style={styles.card}>
          <h2 style={styles.heading}>Hire Worker</h2>

          <select
            style={styles.input}
            value={form.workType}
            onChange={(e) => {
              setForm({ ...form, workType: e.target.value });
              searchWorkers(e.target.value);
            }}
          >
            <option value="">Select Work</option>
            {jobs.map((j, i) => (
              <option key={i}>{j}</option>
            ))}
          </select>

          {workers.length > 0 && (
            <select
              style={styles.input}
              onChange={(e) => {
                const w = workers.find(x => x._id === e.target.value);
                if (!w) return;

                setForm({
                  ...form,
                  labourId: w._id,
                  labourName: w.name
                });
              }}
            >
              <option>Select Worker</option>
              {workers.map(w => (
                <option key={w._id} value={w._id}>
                  {w.name} - {w.city}
                </option>
              ))}
            </select>
          )}

          <input
            style={styles.input}
            placeholder="Location"
            value={form.location}
            onChange={(e) =>
              setForm({ ...form, location: e.target.value })
            }
          />

          <input
            type="date"
            style={styles.input}
            value={form.date}
            onChange={(e) =>
              setForm({ ...form, date: e.target.value })
            }
          />

          <button style={styles.button} onClick={sendRequest}>
            Send Request
          </button>
        </div>

        {/* RIGHT PANEL */}
        <div style={styles.card}>
          <h2 style={styles.heading}>My Requests</h2>

          {requests.length === 0 && (
            <p style={styles.empty}>No requests yet</p>
          )}

          {requests.map(req => (
            <div key={req._id} style={styles.requestCard}>

              <div style={styles.row}>
                <h3 style={styles.orange}>{req.labourName}</h3>
                <span style={styles.badge}>{req.status}</span>
              </div>

              <p style={styles.text}>Work: {req.workType}</p>
              <p style={styles.text}>Location: {req.location}</p>
              <p style={styles.text}>Date: {req.date}</p>

              {req.labourResponse === "Accepted" &&
                req.customerDecision === "Waiting" && (

                <div style={styles.buttonRow}>
                  <button
                    style={styles.accept}
                    onClick={() => customerDecision(req._id, "Accepted")}
                  >
                    Accept
                  </button>

                  <button
                    style={styles.reject}
                    onClick={() => customerDecision(req._id, "Rejected")}
                  >
                    Reject
                  </button>
                </div>
              )}

              {req.customerDecision === "Accepted" && (
                <div style={styles.feedbackBox}>

                  <input
                    type="number"
                    min="1"
                    max="5"
                    placeholder="Rating"
                    style={styles.input}
                    onChange={(e) =>
                      setRequests(requests.map(i =>
                        i._id === req._id
                          ? { ...i, tempRating: e.target.value }
                          : i
                      ))
                    }
                  />

                  <textarea
                    placeholder="Write Review"
                    style={styles.textarea}
                    onChange={(e) =>
                      setRequests(requests.map(i =>
                        i._id === req._id
                          ? { ...i, tempComment: e.target.value }
                          : i
                      ))
                    }
                  />

                  <button
                    style={styles.button}
                    onClick={() =>
                      submitFeedback(req._id, req.tempRating, req.tempComment)
                    }
                  >
                    Submit
                  </button>

                </div>
              )}

            </div>
          ))}

        </div>

      </div>

    </div>
  );
}

/* ================= STYLES ================= */

const styles = {

  page: {
    background: "#0b0f19",
    minHeight: "100vh",
    color: "white"
  },

  container: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "20px",
    padding: "20px",
    maxWidth: "1100px",
    margin: "auto"
  },

  card: {
    background: "#111827",
    padding: "20px",
    borderRadius: "12px",
    border: "1px solid #1f2937"
  },

  heading: {
    color: "#f97316",
    marginBottom: "16px"
  },

  input: {
    width: "100%",
    height: "42px",
    padding: "10px",
    borderRadius: "8px",
    border: "1px solid #374151",
    background: "#1f2937",
    color: "white",
    marginBottom: "10px",
    boxSizing: "border-box"
  },

  button: {
    width: "100%",
    height: "42px",
    background: "#f97316",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer",
    marginTop: "10px"
  },

  requestCard: {
    background: "#1f2937",
    padding: "14px",
    borderRadius: "10px",
    marginBottom: "12px"
  },

  row: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center"
  },

  orange: {
    color: "#f97316",
    margin: 0
  },

  text: {
    margin: "4px 0",
    color: "#d1d5db"
  },

  badge: {
    background: "#374151",
    padding: "4px 8px",
    borderRadius: "6px",
    fontSize: "12px"
  },

  buttonRow: {
    display: "flex",
    gap: "10px",
    marginTop: "10px"
  },

  accept: {
    flex: 1,
    background: "#16a34a",
    border: "none",
    borderRadius: "6px",
    padding: "8px",
    color: "white"
  },

  reject: {
    flex: 1,
    background: "#dc2626",
    border: "none",
    borderRadius: "6px",
    padding: "8px",
    color: "white"
  },

  textarea: {
    width: "100%",
    height: "70px",
    marginTop: "10px",
    borderRadius: "8px",
    padding: "10px",
    background: "#1f2937",
    border: "1px solid #374151",
    color: "white",
    boxSizing: "border-box"
  },

  feedbackBox: {
    marginTop: "10px"
  },

  empty: {
    color: "#9ca3af"
  }
};
